import{_ as t,o,c as a,a3 as n}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"90C. Proposals To Vary Specific Matters","description":"","frontmatter":{"title":"90C. Proposals To Vary Specific Matters","eba":"Mental Health Services 2024-2028","topics":["hours","shift-work","allowances","staffing"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/hours-of-work/90C-proposals-to-vary-specific-matters.md","filePath":"ebas/mental-health/rpn-pen-mho/hours-of-work/90C-proposals-to-vary-specific-matters.md"}'),r={name:"ebas/mental-health/rpn-pen-mho/hours-of-work/90C-proposals-to-vary-specific-matters.md"};function s(i,e,p,l,h,c){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="_90c-proposals-to-vary-specific-matters" tabindex="-1">90C. Proposals To Vary Specific Matters <a class="header-anchor" href="#_90c-proposals-to-vary-specific-matters" aria-label="Permalink to &quot;90C. Proposals To Vary Specific Matters&quot;">​</a></h1><p>90C.1. Application</p><p><strong>(a)</strong> This clause will apply to any proposal by an Employer or Employees to:</p><p><strong>(i)</strong> implement an alternate Four Clear Days Allowance (see clause 93A);</p><p><strong>(ii)</strong> amend the existing staffing profile (other than that contained at clause (102.5(e)(ii)); or</p><p><strong>(iii)</strong> Implement a 12-hour Shift Agreement</p><p><strong>(b)</strong> Nothing in this clause:</p><p><strong>(i)</strong> allows for the unilateral changing of an Employee&#39;s contract of employment. 90C.2. Definitions In this clause:</p><p><strong>(a)</strong> Affected Employee means an Employee in the ward, unit or program to which the proposal relates.</p><p><strong>(b)</strong> EFT neutral means there is no reduction in nursing hours in a ward, unit or program as a result of the proposal. 90C.3. Written proposal (complying and non-complying proposal) The Employer will provide a written proposal to the Affected Employees and, at the same time, both the Secretary of the ANMF and State Secretary of HACSU. The proposal will address, where relevant, the considerations referred to in clause 90C.9 below.</p><p>90C.4. Meaning of Complying Proposal</p><p>In this clause, a complying proposal is a proposal that:</p><p><strong>(a)</strong> is EFT neutral</p><p><strong>(b)</strong> is not a non-complying proposal as described at clause 90C.7 below. 90C.5. Consultation period – complying proposal</p><p>A maximum of three weeks from the date of provision of the information in clause 90C.3will be provided for consultation.</p><p>90C.6. Implementing a complying proposal</p><p><strong>(a)</strong> Genuine majority agrees Except as provided at (c), below, where a genuine majority of Affected Employees agree to a complying proposal at the local level it may be implemented from the beginning of the next roster period. Such agreement will not be unreasonably withheld.</p><p><strong>(b)</strong> Disputes Should there be concern as to the &#39;genuine&#39; nature of the agreement of the affected Employee, or agreement being unreasonably withheld, either party may progress such concerns through the Dispute Resolution Procedure within seven days of the view of the Affected Employees being determined. While the Dispute Resolution Procedure is being conducted work will continue normally according to the usual practice that existed before the dispute, until the dispute is resolved.</p><p><strong>(c)</strong> Exception – flexible work arrangement The requirement at subclause 92C.6(a) does not apply where the complying proposal is facilitating a flexible work arrangement within the meaning of <a href="/eba/ebas/mental-health/common-terms/workplace-rights/65-flexible-working-arrangements.html">clause 65</a> (Flexible Working Arrangements). Following the consultation period at clause</p><p>90C.5, a complying proposal facilitating a flexible work arrangement may be implemented from the beginning of the next roster period. 90C.7. Meaning of Non-Complying Proposal</p><p>In this clause, a non-complying proposal is a proposal about a matter at subclause 90C.1(a) that:</p><p><strong>(a)</strong> is not EFT neutral</p><p><strong>(b)</strong> is non-compliant with the staffing profiles contained with <a href="/eba/ebas/mental-health/schedules/10-minimum-staffing-levels.html">Schedule 10</a></p><p><strong>(c)</strong> reduces shift length; or</p><p><strong>(d)</strong> includes 12-hour shifts. 90C.8. Implementation of a non-complying proposal</p><p><strong>(a)</strong> A maximum of one month from the date of provision of the written proposal will be provided for consultation.</p><p><strong>(b)</strong> Where the Employer, the ANMF, HACSU and the affected Employees agree, the proposal may be implemented from the beginning of the next roster period.</p><p><strong>(c)</strong> Where the Employee(s) do not agree with an Employer&#39;s proposal, a secret ballot of affected Employees will be conducted. If the ballot does not endorse the proposed change, then the proposal will not proceed.</p><p><strong>(d)</strong> Before voting for a permanent 12-hour shift arrangement, Employees must have adequate time to read and discuss the full 12-hour shift trial final evaluation report. 90C.9. Considerations The following are considerations, where relevant, that must be addressed in relation to a proposal referred to in clause 92C.1:</p><p><strong>(a)</strong> consumer/patient profile – consideration of consumer/patient acuity/clinical context, age of the patient, complexity, length of stay and throughput of patients in the clinical setting e.g. emergency admissions, planned admissions and transfers to/from intensive care areas</p><p><strong>(b)</strong> the capacity of nursing staff to complete their duties within existing work hours</p><p><strong>(c)</strong> quality of care/clinical risk including adverse outcomes such as falls (with or without injury), effects of medication, medical co-morbidities, and medication errors (With or without patient consequences);</p><p><strong>(d)</strong> occupational health and safety considerations such as physical environment and staff safety</p><p><strong>(e)</strong> nursing engagement</p><p><strong>(f)</strong> for 12-hour shift proposals, an appropriate evaluation process, with a pre-trial and post-trial comparative analysis, monitoring and review throughout the trial and a final review and evaluation at the trial end; and</p><p><strong>(g)</strong> for 12-hour shift proposals, the proposed trial period (which should be at least 6-12 months). 90C.10. Preservation of Existing Workload Management Proposals A 12-hour shift Agreement that was implemented prior to this Agreement coming into operation remains in effect, subject to the terms of this Agreement.</p>',36)])])}const f=t(r,[["render",s]]);export{g as __pageData,f as default};
